proof fn phi_3_map_union_idempotent<A, B>(s: Set<A>, f: spec_fn(A) -> B)
    ensures
        (s + s).map(f) == s.map(f),
{
    set_map_union(s, s, f);
}

proof fn phi_4_map_union_subset_left<A, B>(s1: Set<A>, s2: Set<A>, f: spec_fn(A) -> B)
    ensures
        s1.map(f).subset_of((s1 + s2).map(f)),
{
    set_map_union(s1, s2, f);
}
